CREATE OR REPLACE FUNCTION public.check_team_member_count()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_count INT;
BEGIN
  -- Only check for team tournaments
  IF NEW.team_id IS NOT NULL THEN
    SELECT COUNT(*) INTO v_count 
    FROM tournament_participants 
    WHERE team_id = NEW.team_id AND team_position IS NOT NULL;

    IF v_count > 2 THEN
      RAISE EXCEPTION 'Team cannot have more than 2 active members';
    END IF;
  END IF;

  RETURN NEW;
END;
$function$

CREATE OR REPLACE FUNCTION public.check_team_member_positions()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_duplicate INT;
BEGIN
  -- Only check for team tournaments
  IF NEW.team_id IS NOT NULL AND NEW.team_position IS NOT NULL THEN
    SELECT COUNT(*) INTO v_duplicate 
    FROM tournament_participants 
    WHERE team_id = NEW.team_id 
      AND team_position = NEW.team_position 
      AND user_id != NEW.user_id;

    IF v_duplicate > 0 THEN
      RAISE EXCEPTION 'Each team position (1 and 2) must be unique';
    END IF;
  END IF;

  RETURN NEW;
END;
$function$

CREATE OR REPLACE FUNCTION public.daily_snapshot_faction_map_statistics()
 RETURNS void
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_yesterday DATE;
  v_rows_created INT;
  v_rows_skipped INT;
BEGIN
  v_yesterday := CURRENT_DATE - INTERVAL '1 day';

  -- Only create snapshot if one doesn't already exist for yesterday
  IF NOT EXISTS (
    SELECT 1 FROM faction_map_statistics_history
    WHERE snapshot_date = v_yesterday
  ) THEN
    SELECT * INTO v_rows_created, v_rows_skipped
    FROM create_faction_map_statistics_snapshot(v_yesterday);

    RAISE NOTICE 'Snapshot created for %: % rows', v_yesterday, v_rows_created;
  ELSE
    RAISE NOTICE 'Snapshot already exists for %', v_yesterday;
  END IF;
END;
$function$

CREATE OR REPLACE FUNCTION public.update_league_tiebreakers(p_tournament_id uuid)
 RETURNS TABLE(updated_count integer, error_message text)
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_updated INT := 0;
  v_error TEXT := NULL;
BEGIN
  UPDATE tournament_participants tp
  SET 
    omp = t.omp,
    gwp = t.gwp,
    ogp = t.ogp
  FROM (SELECT * FROM calculate_league_tiebreakers(p_tournament_id)) t
  WHERE tp.tournament_id = p_tournament_id
    AND tp.user_id = t.user_id;

  GET DIAGNOSTICS v_updated = ROW_COUNT;

  RETURN QUERY SELECT v_updated, v_error;
EXCEPTION WHEN OTHERS THEN
  RETURN QUERY SELECT 0, SQLERRM;
END;
$function$

CREATE OR REPLACE FUNCTION public.update_team_tiebreakers(p_tournament_id uuid)
 RETURNS TABLE(updated_count integer, error_message text)
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_updated INT := 0;
  v_error TEXT := NULL;
BEGIN
  -- Update tournament_teams with calculated tiebreakers
  UPDATE tournament_teams tt
  SET 
    omp = t.omp,
    gwp = t.gwp,
    ogp = t.ogp
  FROM (SELECT * FROM calculate_team_swiss_tiebreakers(p_tournament_id)) t
  WHERE tt.tournament_id = p_tournament_id
