CREATE OR REPLACE FUNCTION public.validate_tournament_match_players()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_tournament_mode VARCHAR;
  v_player1_exists BOOLEAN;
  v_player2_exists BOOLEAN;
BEGIN
  -- Get tournament mode
  SELECT tournament_mode INTO v_tournament_mode
  FROM tournaments
  WHERE id = NEW.tournament_id;

  IF v_tournament_mode = 'team' THEN
    -- Team mode: validate against tournament_teams
    SELECT EXISTS(SELECT 1 FROM tournament_teams WHERE id = NEW.player1_id) INTO v_player1_exists;
    SELECT EXISTS(SELECT 1 FROM tournament_teams WHERE id = NEW.player2_id) INTO v_player2_exists;

    IF NOT v_player1_exists THEN
      RAISE EXCEPTION 'Team % does not exist in tournament_teams', NEW.player1_id;
    END IF;

    IF NOT v_player2_exists THEN
      RAISE EXCEPTION 'Team % does not exist in tournament_teams', NEW.player2_id;
    END IF;
  ELSE
    -- 1v1 mode: validate against users (original FK behavior)
    SELECT EXISTS(SELECT 1 FROM users WHERE id = NEW.player1_id) INTO v_player1_exists;
    SELECT EXISTS(SELECT 1 FROM users WHERE id = NEW.player2_id) INTO v_player2_exists;

    IF NOT v_player1_exists THEN
      RAISE EXCEPTION 'User % does not exist in users table', NEW.player1_id;
    END IF;

    IF NOT v_player2_exists THEN
      RAISE EXCEPTION 'User % does not exist in users table', NEW.player2_id;
    END IF;
  END IF;

  RETURN NEW;
END;
$function$

CREATE OR REPLACE FUNCTION public.validate_tournament_match_results()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_tournament_mode VARCHAR;
  v_winner_exists BOOLEAN;
  v_loser_exists BOOLEAN;
BEGIN
  -- Only validate if winner_id or loser_id is being set
  IF NEW.winner_id IS NULL AND NEW.loser_id IS NULL THEN
    RETURN NEW;
  END IF;

  -- Get tournament mode
  SELECT tournament_mode INTO v_tournament_mode
  FROM tournaments
  WHERE id = NEW.tournament_id;

  IF v_tournament_mode = 'team' THEN
    -- Team mode: validate against tournament_teams
    IF NEW.winner_id IS NOT NULL THEN
      SELECT EXISTS(SELECT 1 FROM tournament_teams WHERE id = NEW.winner_id) INTO v_winner_exists;
      IF NOT v_winner_exists THEN
        RAISE EXCEPTION 'Team (winner_id) % does not exist in tournament_teams', NEW.winner_id;
      END IF;
    END IF;

    IF NEW.loser_id IS NOT NULL THEN
      SELECT EXISTS(SELECT 1 FROM tournament_teams WHERE id = NEW.loser_id) INTO v_loser_exists;
      IF NOT v_loser_exists THEN
        RAISE EXCEPTION 'Team (loser_id) % does not exist in tournament_teams', NEW.loser_id;
      END IF;
    END IF;
  ELSE
    -- 1v1 mode: validate against users (original FK behavior)
    IF NEW.winner_id IS NOT NULL THEN
      SELECT EXISTS(SELECT 1 FROM users WHERE id = NEW.winner_id) INTO v_winner_exists;
      IF NOT v_winner_exists THEN
        RAISE EXCEPTION 'User (winner_id) % does not exist in users table', NEW.winner_id;
      END IF;
    END IF;

    IF NEW.loser_id IS NOT NULL THEN
      SELECT EXISTS(SELECT 1 FROM users WHERE id = NEW.loser_id) INTO v_loser_exists;
      IF NOT v_loser_exists THEN
        RAISE EXCEPTION 'User (loser_id) % does not exist in users table', NEW.loser_id;
      END IF;
    END IF;
  END IF;

  RETURN NEW;
END;
$function$

CREATE OR REPLACE FUNCTION public.validate_tournament_round_match_players()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_tournament_mode VARCHAR;
  v_player1_exists BOOLEAN;
  v_player2_exists BOOLEAN;
  v_winner_exists BOOLEAN;
BEGIN
  -- Get tournament mode
  SELECT t.tournament_mode INTO v_tournament_mode
  FROM tournaments t
  JOIN tournament_rounds tr ON tr.tournament_id = t.id
  WHERE tr.id = NEW.round_id;

  IF v_tournament_mode = 'team' THEN
    -- Team mode: validate against tournament_teams
    SELECT EXISTS(SELECT 1 FROM tournament_teams WHERE id = NEW.player1_id) INTO v_player1_exists;
    SELECT EXISTS(SELECT 1 FROM tournament_teams WHERE id = NEW.player2_id) INTO v_player2_exists;

    IF NOT v_player1_exists THEN
      RAISE EXCEPTION 'Team (player1_id) % does not exist in tournament_teams', NEW.player1_id;
    END IF;

    IF NOT v_player2_exists THEN
      RAISE EXCEPTION 'Team (player2_id) % does not exist in tournament_teams', NEW.player2_id;
    END IF;

    -- Validate winner_id if set
    IF NEW.winner_id IS NOT NULL THEN
      SELECT EXISTS(SELECT 1 FROM tournament_teams WHERE id = NEW.winner_id) INTO v_winner_exists;
      IF NOT v_winner_exists THEN
        RAISE EXCEPTION 'Team (winner_id) % does not exist in tournament_teams', NEW.winner_id;
      END IF;
    END IF;
  ELSE
    -- 1v1 mode: validate against users (original FK behavior)
    SELECT EXISTS(SELECT 1 FROM users WHERE id = NEW.player1_id) INTO v_player1_exists;
    SELECT EXISTS(SELECT 1 FROM users WHERE id = NEW.player2_id) INTO v_player2_exists;

    IF NOT v_player1_exists THEN
      RAISE EXCEPTION 'User (player1_id) % does not exist in users table', NEW.player1_id;
    END IF;

    IF NOT v_player2_exists THEN
      RAISE EXCEPTION 'User (player2_id) % does not exist in users table', NEW.player2_id;
    END IF;

    -- Validate winner_id if set
    IF NEW.winner_id IS NOT NULL THEN
      SELECT EXISTS(SELECT 1 FROM users WHERE id = NEW.winner_id) INTO v_winner_exists;
      IF NOT v_winner_exists THEN
        RAISE EXCEPTION 'User (winner_id) % does not exist in users table', NEW.winner_id;
      END IF;
    END IF;
  END IF;

  RETURN NEW;
END;
$function$
